// Parse RBA / IronPlanet alert email HTML into individual listing objects
const html = $input.item.json.html || $input.item.json.text || '';
const today = new Date().toISOString().slice(0, 10);

if (!html || html.length < 100) return [];

// ── Extract hrefs pointing to rbauction / ironplanet listings ──
const urlRe = /href=["'](https?:\/\/(?:www\.)?(?:rbauction\.com|ironplanet\.com)\/[^"' ]{5,300})["']/gi;
const priceRe = /\$\s*([\d,]+(?:\.\d{2})?)/g;

// Titles: bold/heading tags that look like equipment names
const titleRe = /<(?:h[1-6]|strong|b|td|div|span)[^>]*>\s*([^<]{15,200})\s*<\/(?:h[1-6]|strong|b|td|div|span)>/gi;

const urls = [], prices = [], titles = [];
let m;

while ((m = urlRe.exec(html)) !== null) {
  const u = m[1];
  // Only listing detail pages, skip nav/footer links
  if (/\/(lot|item|listing|equipment)\//.test(u) || /\/[A-Za-z0-9]{6,}$/.test(u)) {
    if (!urls.includes(u)) urls.push(u);
  }
}

while ((m = priceRe.exec(html)) !== null) {
  const p = parseFloat(m[1].replace(/,/g, ''));
  if (p >= 200 && p <= 250000) prices.push(p);
}

while ((m = titleRe.exec(html)) !== null) {
  const t = m[1].trim().replace(/\s+/g, ' ');
  // Filter: must look like equipment (contains typical keywords)
  if (t.length >= 10 && /bucket|thumb|ripper|auger|coupler|attachment|excavator|breaker|compactor|blade|rake|grapple/i.test(t)) {
    titles.push(t);
  }
}

// If no URLs found fall back: treat whole email as one unknown listing
if (urls.length === 0 && prices.length > 0) {
  const subject = $input.item.json.subject || 'RBA Alert';
  return [{
    json: {
      listing_id: 'RBA-EMAIL-' + $input.item.json.id,
      title: subject.slice(0, 255),
      price_cad: prices[0],
      sale_date: today,
      category_raw: 'email-alert',
      url: ''
    }
  }];
}

const results = [];
const count = urls.length;

for (let i = 0; i < count; i++) {
  const url = urls[i];
  const rawId = url.split('/').filter(Boolean).pop().replace(/[^a-zA-Z0-9-]/g, '').slice(-50);
  const listing_id = 'RBA-' + rawId;

  // Match price: use index-matched price, or nearest
  const price_cad = prices[i] ?? prices[0] ?? 0;
  if (price_cad <= 0) continue;

  const title = (
    titles[i] ??
    titles[0] ??
    ($input.item.json.subject || 'RBA Listing').replace(/alert|save search|results/gi, '').trim()
  ).slice(0, 255);

  results.push({
    json: {
      listing_id,
      title,
      price_cad,
      sale_date: today,
      category_raw: 'rba-email-alert',
      location: 'Canada',
      url: url.slice(0, 500)
    }
  });
}

return results;

const listings = $input.item.json.listings || [];
if (listings.length === 0) return [];

// Sort by price ascending (cheapest first)
listings.sort((a, b) => (a.price_cad || 0) - (b.price_cad || 0));

const fmt = (n) => new Intl.NumberFormat('en-CA', {
  style: 'currency', currency: 'CAD', maximumFractionDigits: 0
}).format(n);

const lines = listings.map(l =>
  `📦 *${(l.title || '').slice(0, 80)}*\n` +
  `💰 ${fmt(l.price_cad || 0)}` +
  (l.location ? ` | 📍 ${l.location}` : '') + '\n' +
  (l.url ? `🔗 ${l.url}` : '')
).join('\n\n');

const message = `🏷 *RBA — ${listings.length} 条新拍卖情报*\n\n${lines}\n\n_by n8n WF6_`;
return [{ json: { message, count: listings.length } }];
